const final = {};
let mensagens = [];

for (const item of items) {
  const json = item.json;
  if (json.Mensagem) mensagens.push(json.Mensagem);
  for (const key in json) {
    if (key !== 'Mensagem') final[key] = json[key];
  }
  if (json.From && !final.telefone) {
    final.telefone = json.From;
  }
}

final.Mensagem = mensagens.join(", ");
if (!final.Nome) final.Nome = '';

// Data atual e proximos dias em fuso -03:00
const agora = new Date(Date.now() - 3 * 3600000);
const diasSemNomes = ["domingo","segunda-feira","terca-feira","quarta-feira","quinta-feira","sexta-feira","sabado"];

function formatarData(d) {
  var dia = String(d.getUTCDate()).padStart(2, "0");
  var mes = String(d.getUTCMonth() + 1).padStart(2, "0");
  var ano = d.getUTCFullYear();
  return dia + "/" + mes + "/" + ano;
}

function formatarISO(d) {
  var dia = String(d.getUTCDate()).padStart(2, "0");
  var mes = String(d.getUTCMonth() + 1).padStart(2, "0");
  var ano = d.getUTCFullYear();
  return ano + "-" + mes + "-" + dia;
}

var hoje = diasSemNomes[agora.getUTCDay()];
final.dataAtual = hoje + " " + formatarData(agora);
final.dataISO = formatarISO(agora);

// Proximos 7 dias com nome + data exata
var proximos = [];
for (var i = 1; i <= 7; i++) {
  var d = new Date(agora.getTime() + i * 86400000);
  proximos.push(diasSemNomes[d.getUTCDay()] + " = " + formatarData(d) + " (ISO: " + formatarISO(d) + ")");
}
final.proximosDias = proximos.join(" | ");

return [{ json: final }];

