// Convert binary audio to base64 for Gemini API
const items = $input.all();
const results = [];

for (const item of items) {
  const binaryData = item.binary?.data;
  if (!binaryData) {
    throw new Error('No binary data found in input');
  }

  // Get base64 from binary data (n8n stores it as base64 internally)
  const base64 = binaryData.data;
  const mimeType = binaryData.mimeType || 'audio/ogg';

  results.push({
    json: {
      base64: base64,
      mimetype: mimeType
    }
  });
}

return results;

// Download audio binary from Meta Graph API and convert to base64
const mediaUrl = $input.first().json.url;
const mimeType = $input.first().json.mime_type || 'audio/ogg';
const token = '{{ $env.META_WHATSAPP_TOKEN }}';

const response = await fetch(mediaUrl, {
  headers: { 'Authorization': 'Bearer ' + token }
});

if (!response.ok) {
  throw new Error('Failed to download audio: ' + response.status + ' ' + response.statusText);
}

const buffer = await response.arrayBuffer();
const base64 = Buffer.from(buffer).toString('base64');

return [{
  json: {
    base64: base64,
    mimetype: mimeType,
    audioUrl: mediaUrl
  }
}];

